import React, { useState, useEffect, useContext } from 'react';
import { db} from '../firebase/config';
import { doc, setDoc, onSnapshot } from 'firebase/firestore';

import { Upload } from 'lucide-react';
import { ToastContext } from '../App';
import './CategoryManager.css';

const DEFAULT_ROWS = {
  categories_row1: [
    { id:'rings',     label:'Rings',     image:'https://images.unsplash.com/photo-1605100804763-247f67b3557e?w=600&q=80' },
    { id:'necklaces', label:'Necklaces', image:'https://images.unsplash.com/photo-1599459183200-59c7687a0c70?w=600&q=80' },
    { id:'earrings',  label:'Earrings',  image:'https://images.unsplash.com/photo-1573408301185-9519f94815b9?w=600&q=80' },
    { id:'bracelets', label:'Bracelets', image:'https://images.unsplash.com/photo-1611591437281-460bfbe1220a?w=600&q=80' },
  ],
  categories_row2: [
    { id:'watches',  label:'Watches',   image:'https://images.unsplash.com/photo-1523170335258-f5ed11844a49?w=600&q=80' },
    { id:'anklets',  label:'Anklets',   image:'https://images.unsplash.com/photo-1515562141207-7a88fb7ce338?w=600&q=80' },
    { id:'charms',   label:'Charms',    image:'https://images.unsplash.com/photo-1602751584552-8ba73aad10e1?w=600&q=80' },
    { id:'pendants', label:'Pendants',  image:'https://images.unsplash.com/photo-1535632066927-ab7c9ab60908?w=600&q=80' },
  ],
};

const FEATURE_DEFAULTS = {
  feature_panel1: {
    title: 'Timeless Elegance',
    sub:   'Discover our collection of ethically sourced, handcrafted jewelry designed for the modern muse.',
    image: 'https://images.unsplash.com/photo-1531746020798-e6953c6e8e04?w=800&q=80',
  },
  feature_panel2: {
    title: 'The Bridal Edit',
    sub:   'Celebrate love with pieces crafted for the most precious moments of your life.',
    image: 'https://images.unsplash.com/photo-1519741347686-c1e0aadf4611?w=800&q=80',
  },
};

export default function CategoryManager() {
  const { showToast } = useContext(ToastContext);
  const [rows,    setRows]    = useState(DEFAULT_ROWS);
  const [panels,  setPanels]  = useState(FEATURE_DEFAULTS);
  const [uploading, setUploading] = useState({});

  useEffect(() => {
    const unsubs = [];
    Object.keys(DEFAULT_ROWS).forEach(docId => {
      unsubs.push(onSnapshot(doc(db,'site',docId), snap => {
        if (snap.exists()) setRows(r => ({...r, [docId]: snap.data().items}));
      }));
    });
    Object.keys(FEATURE_DEFAULTS).forEach(docId => {
      unsubs.push(onSnapshot(doc(db,'site',docId), snap => {
        if (snap.exists()) setPanels(p => ({...p, [docId]: snap.data()}));
      }));
    });
    return () => unsubs.forEach(u => u());
  }, []);

  /* ── upload image for a category tile ── */
  const uploadCatImage = (docId, idx, file) => {
    const key = `${docId}_${idx}`;
    const storageRef = ref(storage, `categories/${Date.now()}_${file.name}`);
    const task = uploadBytesResumable(storageRef, file);
    setUploading(u => ({...u, [key]: 0}));
    task.on('state_changed',
      snap => setUploading(u => ({...u, [key]: Math.round(snap.bytesTransferred/snap.totalBytes*100)})),
      () => { showToast('Upload failed','error'); setUploading(u => ({...u, [key]: null})); },
      async () => {
        const url = await getDownloadURL(task.snapshot.ref);
        const updated = [...rows[docId]];
        updated[idx] = { ...updated[idx], image: url };
        await setDoc(doc(db,'site',docId), { items: updated });
        setUploading(u => ({...u, [key]: null}));
        showToast(`${updated[idx].label} image updated! Live on client now.`);
      }
    );
  };

  /* ── upload feature panel image ── */
  const uploadPanelImage = (panelId, file) => {
    const storageRef = ref(storage, `panels/${Date.now()}_${file.name}`);
    const task = uploadBytesResumable(storageRef, file);
    setUploading(u => ({...u, [panelId]: 0}));
    task.on('state_changed',
      snap => setUploading(u => ({...u, [panelId]: Math.round(snap.bytesTransferred/snap.totalBytes*100)})),
      () => { showToast('Upload failed','error'); setUploading(u=>({...u,[panelId]:null})); },
      async () => {
        const url = await getDownloadURL(task.snapshot.ref);
        const updated = { ...panels[panelId], image: url };
        await setDoc(doc(db,'site',panelId), updated);
        setUploading(u => ({...u, [panelId]: null}));
        showToast('Feature panel image updated!');
      }
    );
  };

  /* ── update panel text ── */
  const updatePanelText = async (panelId, field, value) => {
    const updated = { ...panels[panelId], [field]: value };
    setPanels(p => ({...p, [panelId]: updated}));
    await setDoc(doc(db,'site',panelId), updated);
    showToast('Text updated!');
  };

  const ROW_LABELS = { categories_row1: 'Row 1 — Rings, Necklaces, Earrings, Bracelets', categories_row2: 'Row 2 — Watches, Anklets, Charms, Pendants' };
  const PANEL_LABELS = { feature_panel1: 'Feature Panel 1 (Row 1)', feature_panel2: 'Feature Panel 2 (Row 2)' };

  return (
    <div className="cat-manager">
      <div className="page-header">
        <div>
          <h1 className="page-title">Categories</h1>
          <p className="page-sub">Update category images and feature panel content. Changes go live instantly.</p>
        </div>
      </div>

      {/* CATEGORY TILES */}
      {Object.keys(DEFAULT_ROWS).map(docId => (
        <div key={docId} className="card cat-section">
          <h3 className="section-heading">{ROW_LABELS[docId]}</h3>
          <div className="cat-tiles">
            {(rows[docId] || []).map((cat, idx) => {
              const key = `${docId}_${idx}`;
              const prog = uploading[key];
              return (
                <div className="cat-tile" key={cat.id}>
                  <div className="cat-tile-img">
                    <img src={cat.image} alt={cat.label} />
                    <label className="cat-upload-btn">
                      <input type="file" accept="image/*" style={{display:'none'}}
                        onChange={e => uploadCatImage(docId, idx, e.target.files[0])} />
                      <Upload size={14}/> Change
                    </label>
                    {prog !== null && prog !== undefined && (
                      <div className="tile-progress">
                        <div style={{width:`${prog}%`, height:'100%', background:'#fff', opacity:0.4, transition:'width 0.3s'}}/>
                      </div>
                    )}
                  </div>
                  <p className="cat-tile-label">{cat.label}</p>
                </div>
              );
            })}
          </div>
        </div>
      ))}

      {/* FEATURE PANELS */}
      {Object.keys(FEATURE_DEFAULTS).map(panelId => {
        const panel = panels[panelId];
        const prog  = uploading[panelId];
        return (
          <div key={panelId} className="card cat-section">
            <h3 className="section-heading">{PANEL_LABELS[panelId]}</h3>
            <div className="panel-editor">
              <div className="panel-img-wrap">
                <img src={panel.image} alt="panel" />
                <label className="panel-upload-btn">
                  <input type="file" accept="image/*" style={{display:'none'}}
                    onChange={e => uploadPanelImage(panelId, e.target.files[0])} />
                  <Upload size={14}/> Change Image
                </label>
                {prog !== null && prog !== undefined && (
                  <div className="tile-progress">
                    <div style={{width:`${prog}%`, height:'100%', background:'#fff', opacity:0.4, transition:'width 0.3s'}}/>
                  </div>
                )}
              </div>
              <div className="panel-fields">
                <div className="form-field">
                  <label className="field-label">Title</label>
                  <input className="field-input" defaultValue={panel.title}
                    onBlur={e => updatePanelText(panelId,'title',e.target.value)} />
                </div>
                <div className="form-field" style={{marginTop:14}}>
                  <label className="field-label">Subtitle Text</label>
                  <textarea className="field-input" rows={3} defaultValue={panel.sub}
                    onBlur={e => updatePanelText(panelId,'sub',e.target.value)}
                    style={{resize:'vertical'}} />
                </div>
                <p className="panel-hint">Click outside the field to save text changes.</p>
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}
